```javascript
function compoundInterest(base, rate, years, times) {
  return base * Math.pow(1 + rate / (times * 100), years * times);
}

// Example usage: Get input for parameters
const base = parseFloat(prompt("Enter initial investment:"));
const rate = parseFloat(prompt("Enter annual interest rate (%):"));
const years = parseFloat(prompt("Enter number of years:"));
const times = parseFloat(prompt("Enter number of compounding periods per year:"));

// Calculate and display the result
const result = compoundInterest(base, rate, years, times);
console.log(`Final amount after ${years} years: $${result.toFixed(2)}`);
```

